//! Versioned JSON IR for the bounded resolution-lift slice (hardware-facing).

use serde::{Deserialize, Serialize};

pub const IR_VERSION: &str = "sieve_fsm_v0";

#[derive(Debug, Clone, Serialize, Deserialize, PartialEq, Eq)]
pub struct SieveFsmIrV0 {
    pub ir_version: String,
    pub heads: u16,
    pub coupling: u16,
    pub observer_resolution: u16,
    pub residue_threshold: u16,
}

impl SieveFsmIrV0 {
    pub fn new(
        heads: u16,
        coupling: u16,
        observer_resolution: u16,
        residue_threshold: u16,
    ) -> Self {
        Self {
            ir_version: IR_VERSION.to_string(),
            heads,
            coupling,
            observer_resolution,
            residue_threshold,
        }
    }
}

#[derive(Debug, Clone, Serialize, Deserialize, PartialEq, Eq)]
pub struct LiftOutcomeV0 {
    pub lift: bool,
    pub after_observer_resolution: u16,
}
